  ('pukao-6f0ba476-moex-00199', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法規定納稅義務人應納稅捐，於繳納期間屆滿三十日後仍未繳納者，由稅捐稽徵機關移 送強制執行。但於某些條件下暫緩移送強制執行，下列何者錯誤？', '["已依稅捐稽徵法第35條規定申請復查者", "納稅義務人對復查決定之應納稅額繳納三分之一，並依法提起訴願", "納稅義務人對復查決定之應納稅額繳納三分之一稅額確有困難，經稅捐稽徵機關核准，提供相 當擔保", "已依稅捐稽徵法提起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00200', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行法規，下列何者屬於低稅負國家或地區？', '["僅對其境內來源所得課稅之地區或國家", "營利事業所得稅或實質類似租稅稅率為20%之地區或國家", "營利事業所得稅或實質類似租稅稅率為17%之地區或國家", "營利事業所得稅或實質類似租稅稅率為15%之地區或國家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00201', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '所得稅法中的固定資產、遞耗資產以及無形資產遇到物價上漲至少達多少時，得實施資產重估 價？', '["10%", "20%", "25%", "50%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00202', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '關於自用住宅用地地價稅之敘述，下列何者錯誤？', '["繼承土地之土地所有權人欲享有自用住宅之優惠稅率，應於繼承後四十日前提出申請", "自用住宅用地，其地價稅按千分之二計徵", "自用住宅用地，指土地所有權人或其配偶、直系親屬於該地辦竣戶籍登記，且無出租或供營業 用之住宅用地", "企業或公營事業興建之勞工宿舍，自動工興建或取得土地所有權之日起，其用地之地價稅按千 分之二計徵"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00203', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '納稅義務人對依遺產及贈與稅法規定應申報之遺產或贈與財產，已依規定申報而有漏報或短報情 事者，罰則為何？', '["按核定應納稅額加處二倍以下之罰鍰", "處以所漏稅額一倍至三倍之罰鍰", "按所漏稅額加處二倍以下之罰鍰", "按所漏稅額處以二倍以下之罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00204', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列各款何者符合可從遺產總額扣除之規定？①被繼承人遺有父母者  ②被繼承人遺有配偶者', '["被繼承人遺有兄弟姊妹、祖父母者", "執行遺囑及管理遺產之直接必要費用  ⑤被繼承人死亡 前，未償之債務，具有確實之證明者", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00205', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列何者不屬於營利所得？', '["與人合夥經營早餐店之盈餘", "醫生自行開設診所之獲利", "股東所獲分配之公司股利", "合作社社員所獲分配之盈餘"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00206', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '甲為以營利為目的之網路賣家，每月銷售額15萬元，下列敘述何者錯誤？', '["應依法課徵營業稅", "需向國稅局辦理稅籍登記", "按銷售額依稅率1%，由國稅局按季開徵", "需依照國稅局核定使用統一發票"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00207', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '營業人漏開統一發票之罰則為何？', '["按規定稅率計算稅額繳納稅款，並按該稅額處五倍以下罰鍰；但處罰金額不得超過新臺幣一百 萬元", "處新臺幣三千元以上三萬元以下罰鍰", "停止營業", "處新臺幣一千五百元以上一萬五千元以下罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00208', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '何者合乎所得基本稅額條例？①課徵對象為營利事業  ②為最低稅負制  ③課徵對象為個人', '["申報期間為每年六月  ⑤非中華民國境內居住之個人不適用  ⑥獨資或合夥組織之營利事業 不適用", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "b5d36143eef6", "answer_pdf_sha1": "cd7aba67d90c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
